import React from 'react';
import { useMediaQuery } from './useMediaQuery';
import './styles.css';

export default function App() {
  const isMobile = useMediaQuery('(max-width: 768px)');
  const isTablet = useMediaQuery('(min-width: 769px) and (max-width: 1024px)');
  const isDesktop = useMediaQuery('(min-width: 1025px)');
  const prefersDark = useMediaQuery('(prefers-color-scheme: dark)');

  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1rem' }}>useMediaQuery</h1>
      <ul className="mq-list">
        <li>Mobile (≤768px): <strong data-testid="result">{isMobile ? 'Yes' : 'No'}</strong></li>
        <li>Tablet (769–1024px): <strong>{isTablet ? 'Yes' : 'No'}</strong></li>
        <li>Desktop (≥1025px): <strong>{isDesktop ? 'Yes' : 'No'}</strong></li>
        <li>Prefers dark: <strong>{prefersDark ? 'Yes' : 'No'}</strong></li>
      </ul>
      <p className="mq-hint">Resize your browser to see values change.</p>
    </div>
  );
}

