import { render, screen, act } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import { useMediaQuery } from './useMediaQuery';

function Harness({ query }: { query: string }) {
  const matches = useMediaQuery(query);
  return <span data-testid="result">{matches ? 'yes' : 'no'}</span>;
}

describe('useMediaQuery', () => {
  let listeners: Array<(e: { matches: boolean }) => void>;
  let mockMql: any;

  beforeEach(() => {
    listeners = [];
    mockMql = {
      matches: false,
      addEventListener: jest.fn((event: string, cb: any) => { listeners.push(cb); }),
      removeEventListener: jest.fn((event: string, cb: any) => {
        listeners = listeners.filter(l => l !== cb);
      }),
    };
    window.matchMedia = jest.fn().mockReturnValue(mockMql);
  });

  it('returns false when query does not match', () => {
    mockMql.matches = false;
    render(<Harness query="(max-width: 768px)" />);
    expect(screen.getByTestId('result')).toHaveTextContent('no');
  });

  it('returns true when query matches', () => {
    mockMql.matches = true;
    render(<Harness query="(max-width: 768px)" />);
    expect(screen.getByTestId('result')).toHaveTextContent('yes');
  });

  it('updates when media query changes', () => {
    mockMql.matches = false;
    render(<Harness query="(max-width: 768px)" />);
    expect(screen.getByTestId('result')).toHaveTextContent('no');
    act(() => {
      listeners.forEach(cb => cb({ matches: true }));
    });
    expect(screen.getByTestId('result')).toHaveTextContent('yes');
  });

  it('cleans up listener on unmount', () => {
    const { unmount } = render(<Harness query="(max-width: 768px)" />);
    expect(mockMql.addEventListener).toHaveBeenCalled();
    unmount();
    expect(mockMql.removeEventListener).toHaveBeenCalled();
  });

  it('re-subscribes when query changes', () => {
    const { rerender } = render(<Harness query="(max-width: 768px)" />);
    const firstCallCount = (mockMql.addEventListener as jest.Mock).mock.calls.length;
    rerender(<Harness query="(max-width: 1024px)" />);
    expect((mockMql.addEventListener as jest.Mock).mock.calls.length).toBeGreaterThan(firstCallCount);
  });
});

